/**
 * Client-side port of `POST /ground-material/clean-v3`.
 *
 * 1:1 with the golden-tested Rust reference
 * `ir-simprep::{ground_clean,ground_clip}` (infrared-core). NOT ported from the
 * Python — the Rust's documented parity quirks (columnized props, positional
 * ids, GEOS ring reordering on clip; deviations D5–D8) ARE the contract.
 *
 * Pure, synchronous, universal-runtime (no I/O, no `node:` imports).
 */

import polygonClipping from 'polygon-clipping'
import { GroundMaterialsServiceError } from '../errors'
import type { FeatureCollection, MaterialLayers } from './service'

/** osmnx `bbox_from_point` Earth radius (the 4th radius constant in the stack;
 *  it defines this endpoint's crop extent). Mirror of ir-geo OSMNX_EARTH_RADIUS_M. */
const OSMNX_EARTH_RADIUS_M = 6371009.0
/** Bit-identical to infrared-core ir_geo::consts::DEG2RAD in IEEE-754. */
const DEG2RAD = Math.PI / 180
const RAD2DEG = 180 / Math.PI

/**
 * osmnx-compatible bbox `(west, south, east, north)` around a lat/lon point,
 * `distance` meters in each direction. 1:1 port of
 * ir-simprep::ground_clean::bbox_from_point.
 *
 * Latitude is clamped to ±89.9° ONCE; the clamped value feeds BOTH the cos()
 * in the longitude delta AND the south/north edges (Rust shadows the variable).
 */
export function bboxFromPoint(
  latitude: number,
  longitude: number,
  distance: number,
): [number, number, number, number] {
  const lat = Math.min(Math.max(latitude, -89.9), 89.9)
  const deltaLat = (distance / OSMNX_EARTH_RADIUS_M) * RAD2DEG
  const deltaLon = ((distance / OSMNX_EARTH_RADIUS_M) * RAD2DEG) / Math.cos(lat * DEG2RAD)
  return [longitude - deltaLon, lat - deltaLat, longitude + deltaLon, lat + deltaLat]
}

export type Bbox = [number, number, number, number]

export interface Feature {
  type?: string
  id?: string
  properties?: Record<string, unknown> | null
  geometry?: { type?: string; coordinates?: unknown } | null
  [k: string]: unknown
}

type Layer = FeatureCollection

/** Union of property keys across features, first-appearance order (the
 *  GeoDataFrame column set). Computed PRE-crop over ALL input features. */
export function collectPropertyKeys(features: Feature[]): string[] {
  const seen = new Set<string>()
  const keys: string[] = []
  for (const f of features) {
    const props = f?.properties
    if (props && typeof props === 'object') {
      for (const k of Object.keys(props)) {
        if (!seen.has(k)) {
          seen.add(k)
          keys.push(k)
        }
      }
    }
  }
  return keys
}

/** True if every position in the geometry lies inside the bbox (inclusive). */
function geometryWithinBbox(geometry: Feature['geometry'], bbox: Bbox): boolean {
  const scan = (coords: unknown): boolean => {
    if (!Array.isArray(coords)) return true
    if (coords.length === 0) return true
    if (typeof coords[0] === 'number') {
      const x = coords[0] as number
      const y = coords[1] as number
      if (typeof x !== 'number' || typeof y !== 'number') return false
      return x >= bbox[0] && x <= bbox[2] && y >= bbox[1] && y <= bbox[3]
    }
    return coords.every((c) => scan(c))
  }
  return geometry != null && 'coordinates' in geometry && scan(geometry.coordinates)
}

/**
 * Crop a layer's features to the bbox. Contained geometry passes through
 * byte-exact; boundary-crossers are clipped in the clip step (here they are
 * dropped unless fully contained — the polygon-clipping intersection is wired
 * in `clipGeometry`). Columnizes properties over the PRE-crop key union and
 * assigns pre-drop positional string ids. 1:1 with ir-simprep ground_clip.
 */
export function cropLayer(layerName: string, layer: Layer, bbox: Bbox): Feature[] {
  const features = (layer?.features ?? []) as Feature[]
  if (features.length === 0) return []
  const propertyKeys = collectPropertyKeys(features)
  const out: Feature[] = []
  features.forEach((feature, idx) => {
    if (feature.geometry === undefined) {
      throw new Error(`ground-material layer ${layerName}: feature ${idx} has no geometry`)
    }
    const clipped = clipGeometry(feature.geometry, bbox)
    if (clipped == null) return // outside bbox / empty intersection — dropped
    const inProps = (feature.properties ?? {}) as Record<string, unknown>
    // Prototype-safe columnization. Properties arrive from Mapbox/OSM/user
    // GeoJSON via JSON.parse, which can create a real own `__proto__` (or
    // `constructor` etc.) key. Reading with `key in obj` would walk the
    // prototype chain (a sibling lacking own `__proto__` would read
    // `Object.prototype` instead of null), and `properties['__proto__'] = v`
    // would invoke the inherited setter and corrupt the output's prototype.
    // `hasOwnProperty.call` + `defineProperty` avoid both — matching Rust's
    // `serde_json::Map` semantics (no prototype chain).
    const properties: Record<string, unknown> = {}
    for (const key of propertyKeys) {
      const has = Object.prototype.hasOwnProperty.call(inProps, key)
      Object.defineProperty(properties, key, {
        value: has ? inProps[key] : null,
        writable: true,
        enumerable: true,
        configurable: true,
      })
    }
    out.push({ id: String(idx), type: 'Feature', properties, geometry: clipped })
  })
  return out
}

/**
 * Clip one GeoJSON geometry to the bbox. Contained geometry is returned
 * untouched (byte-exact pass-through, like GEOS clip-by-rect). Boundary-crossing
 * Polygon/MultiPolygon are clipped via polygon-clipping (Martinez–Rueda); a
 * non-polygonal crosser is dropped (the downstream type filter would remove it
 * from v3 output anyway). Returns null when nothing remains.
 *
 * polygon-clipping's runtime export is the default (the `.d.ts` mis-declares it
 * as named exports); imported as a default binding accordingly.
 */
function clipGeometry(geometry: Feature['geometry'], bbox: Bbox): Feature['geometry'] | null {
  if (geometryWithinBbox(geometry, bbox)) return geometry
  const gtype = geometry?.type
  const coords = geometry?.coordinates
  if (coords == null) return null

  // polygon-clipping MultiPolygon = Polygon[]; Polygon = Ring[]; Ring = [x,y][]
  type Ring = [number, number][]
  type PolygonGeom = Ring[]
  type MultiPolygonGeom = PolygonGeom[]
  let subject: MultiPolygonGeom
  if (gtype === 'Polygon') subject = [coords as PolygonGeom]
  else if (gtype === 'MultiPolygon') subject = coords as MultiPolygonGeom
  else return null

  const [west, south, east, north] = bbox
  const rect: PolygonGeom = [
    [
      [west, south],
      [east, south],
      [east, north],
      [west, north],
      [west, south],
    ],
  ]

  let clipped: MultiPolygonGeom
  try {
    clipped = polygonClipping.intersection(subject, [rect]) as MultiPolygonGeom
  } catch {
    // DEVIATIONS.md D8: polygon-clipping may throw on self-intersecting input —
    // drop the feature rather than take down the whole job (mirrors Rust
    // catch_unwind).
    return null
  }

  const parts = clipped.filter((poly) => Array.isArray(poly[0]) && poly[0].length > 0)
  if (parts.length === 0) return null
  if (parts.length === 1) return { type: 'Polygon', coordinates: parts[0] }
  return { type: 'MultiPolygon', coordinates: parts }
}

// --- clean-v3 assembly ----------------------------------------------------

export interface CleanV3Params {
  latitude: number
  longitude: number
  distance: number
  defaultLayer?: string
  zStep?: number
}

const DEFAULT_LAYER = 'asphalt'
/** DEVIATIONS.md D5 default is 0.05, but the deployed remote + golden fixtures
 *  use 0.00001. Local default matches the fixtures for provable parity;
 *  forge-kit passes 0.05 explicitly. */
const DEFAULT_Z_STEP = 0.00001

/** Recursively replace leaf [x,y(,…)] positions with [x, y, z]. Malformed
 *  1-element positions are left unchanged (no throw) — mirror of stamp_coords. */
function stampCoords(coords: unknown, z: number): unknown {
  if (!Array.isArray(coords) || coords.length === 0) return coords
  if (typeof coords[0] === 'number') {
    if (coords.length < 2 || typeof coords[1] !== 'number') return coords
    return [coords[0], coords[1], z]
  }
  return coords.map((c) => stampCoords(c, z))
}

function stampFeature(feature: Feature, z: number): void {
  if (feature.geometry && 'coordinates' in feature.geometry) {
    feature.geometry.coordinates = stampCoords(feature.geometry.coordinates, z)
  }
}

function bboxFeature(west: number, south: number, east: number, north: number): Feature {
  return {
    type: 'Feature',
    id: 'default_bbox',
    properties: {},
    geometry: {
      type: 'Polygon',
      coordinates: [
        [
          [west, south],
          [east, south],
          [east, north],
          [west, north],
          [west, south],
        ],
      ],
    },
  }
}

function isPolygonal(feature: Feature): boolean {
  const t = feature.geometry?.type
  return t === 'Polygon' || t === 'MultiPolygon'
}

function featureCollection(features: Feature[]): FeatureCollection {
  return { type: 'FeatureCollection', features: features as never }
}

/**
 * Client-side port of `POST /ground-material/clean-v3`. Pure, synchronous.
 * Iterates layers in INSERTION order (z depends on order — never raw
 * Object.keys, which would hoist integer-like keys); crops + filters to
 * Polygon/MultiPolygon; z-stamps each layer at `(i+1)*zStep`; inserts the
 * bbox default feature. 1:1 with ir-simprep::ground_clean::clean_v3.
 */
export function cleanV3Local(layers: MaterialLayers, params: CleanV3Params): MaterialLayers {
  const zStep = params.zStep ?? DEFAULT_Z_STEP
  const defaultName = params.defaultLayer ?? DEFAULT_LAYER
  const [west, south, east, north] = bboxFromPoint(
    params.latitude,
    params.longitude,
    params.distance,
  )
  const bbox: Bbox = [west, south, east, north]

  // Ordered entries captured at the boundary — NEVER raw Object.keys iteration
  // (integer-like keys would reorder and scramble z).
  const entries = Object.entries(layers)
  const out: MaterialLayers = {}
  let defaultFeature: Feature | null = bboxFeature(west, south, east, north)

  entries.forEach(([name, layer], i) => {
    const z = (i + 1) * zStep
    let features: Feature[]
    try {
      features = cropLayer(name, layer, bbox)
    } catch (err) {
      throw new GroundMaterialsServiceError(err instanceof Error ? err.message : String(err), {
        statusCode: 0,
        responseBody: '',
        operation: 'cleanLocal',
      })
    }
    features = features.filter(isPolygonal)
    for (const f of features) stampFeature(f, z)
    if (name === defaultName && defaultFeature) {
      stampFeature(defaultFeature, z)
      features.unshift(defaultFeature)
      defaultFeature = null
    }
    out[name] = featureCollection(features)
  })

  if (defaultFeature) {
    stampFeature(defaultFeature, 0)
    out[defaultName] = featureCollection([defaultFeature])
  }
  return out
}
