/**
 * GroundMaterialCleaner — the swappable clean-v3 seam.
 *
 * `cleanV3` returns a Promise so a caller can run the work anywhere (inline, a
 * worker, WASM) without the SDK knowing. Two impls ship here:
 *   - RemoteCleaner: the existing `POST /ground-material/clean-v3` gateway call.
 *   - LocalCleaner:  the pure client-side port (`cleanV3Local`).
 * A future WASM cleaner (infrared-core) implements the same interface — one
 * injected object, no call-site churn.
 */

import { GroundMaterialsServiceError } from '../errors'
import type { HttpClient } from '../http'
import { cleanV3Local, type CleanV3Params } from './clean-v3-local'
import type { MaterialLayers } from './service'

export type { CleanV3Params } from './clean-v3-local'

/** Pluggable clean-v3 backend. */
export interface GroundMaterialCleaner {
  cleanV3(layers: MaterialLayers, params: CleanV3Params): Promise<MaterialLayers>
}

/** Runs the pure client-side port inline. */
export class LocalCleaner implements GroundMaterialCleaner {
  cleanV3(layers: MaterialLayers, params: CleanV3Params): Promise<MaterialLayers> {
    return Promise.resolve(cleanV3Local(layers, params))
  }
}

export interface RemoteCleanerDeps {
  httpClient: Pick<HttpClient, 'post'>
}

/** Wraps the existing `POST /ground-material/clean-v3` gateway call. */
export class RemoteCleaner implements GroundMaterialCleaner {
  constructor(private deps: RemoteCleanerDeps) {}

  async cleanV3(layers: MaterialLayers, params: CleanV3Params): Promise<MaterialLayers> {
    const data = await this.deps.httpClient.post<MaterialLayers & { error?: string; traceback?: string }>(
      '/ground-material/clean-v3',
      {
        latitude: params.latitude,
        longitude: params.longitude,
        distance: params.distance,
        layers,
        default: params.defaultLayer ?? 'asphalt',
      },
      { serializeNames: false, bigPayload: true },
    )
    if (!data) return {}
    if (data.error && data.traceback) {
      throw new GroundMaterialsServiceError(
        `Ground materials clean error at (${params.latitude}, ${params.longitude}): ${data.error}`,
        { statusCode: 0, responseBody: data.traceback ?? '', operation: 'clean' },
      )
    }
    const { error: _e, traceback: _t, ...cleaned } = data as Record<string, unknown>
    void _e
    void _t
    return cleaned as MaterialLayers
  }
}

export function resolveCleaner(
  sel: 'remote' | 'local' | GroundMaterialCleaner,
  deps: RemoteCleanerDeps,
): GroundMaterialCleaner {
  if (sel === 'local') return new LocalCleaner()
  if (sel === 'remote') return new RemoteCleaner(deps)
  // Custom object: validate at the injection point so a malformed cleaner
  // fails with a clear message rather than an opaque error deep in getArea.
  if (!sel || typeof sel.cleanV3 !== 'function') {
    throw new TypeError(
      "Invalid ground-materials cleaner: expected 'remote', 'local', or an object with a cleanV3(layers, params) method",
    )
  }
  return sel
}
