/**
 * Geographic extent of a merged area grid — TypeScript port of Python SDK
 * `_area/_merging.py::_compute_grid_bounds` (#122).
 *
 * The merger anchors the merged grid at the polygon bbox SW corner and extends
 * NE by `(numRows * stepM, numCols * stepM)`. When a polygon side isn't an
 * integer multiple of the step, the grid is padded past the polygon — so
 * rendering `mergedGrid` over `polygon.bounds` squashes it. This reports the
 * TRUE extent for correct placement.
 */

import { arrayMax, arrayMin } from '../utils'
import type { TilingConfig } from './config'
import { METERS_PER_DEG_LAT } from './types'

/** Minimal structural shape of a GeoJSON Polygon (first ring is the exterior). */
interface PolygonLike {
  coordinates?: ReadonlyArray<ReadonlyArray<readonly number[]>>
}

/**
 * Compute `[minLng, minLat, maxLng, maxLat]` for the merged grid, or
 * `undefined` when no grid was produced (empty rows/cols or no polygon ring).
 * Mirrors Python's math operand-for-operand for cross-SDK parity.
 */
export function computeGridBounds(
  polygon: PolygonLike | null | undefined,
  numRows: number,
  numCols: number,
  config: TilingConfig,
): [number, number, number, number] | undefined {
  if (numRows <= 0 || numCols <= 0) return undefined

  const ring = polygon?.coordinates?.[0]
  if (!ring || ring.length === 0) return undefined

  const lngs: number[] = []
  const lats: number[] = []
  for (const pt of ring) {
    if (!pt || pt.length < 2) continue
    lngs.push(pt[0])
    lats.push(pt[1])
  }
  if (lngs.length === 0 || lats.length === 0) return undefined

  const minLng = arrayMin(lngs)
  const minLat = arrayMin(lats)
  const maxLat = arrayMax(lats)

  // Use config.stepM directly (operand-for-operand with Python's config.step_m).
  const stepM = config.stepM
  const centerLat = (minLat + maxLat) / 2.0
  const mPerDegLng = METERS_PER_DEG_LAT * Math.cos((centerLat * Math.PI) / 180)
  const stepY = stepM / METERS_PER_DEG_LAT
  const stepX = mPerDegLng !== 0 ? stepM / mPerDegLng : stepM / METERS_PER_DEG_LAT

  const gridMaxLng = minLng + numCols * stepX
  const gridMaxLat = minLat + numRows * stepY
  return [minLng, minLat, gridMaxLng, gridMaxLat]
}
