/**
 * Pre-flight check for direct-sun-hours context-buffer adequacy.
 *
 * Mirrors `infrared_sdk/preflight/sun_context.py` from the Python SDK.
 *
 * The SDK's solar tiling fetches buildings within a fixed margin of each
 * tile (`contextSizeM`). Buildings beyond that margin can't cast shadows
 * into the tile's inference area, so at low sun angles results may
 * degrade at tile edges. This module estimates whether that geometric
 * loss is material for a given (location, time-period, buffer) combo
 * and returns a severity verdict the caller can render as a banner.
 *
 * The estimate is deliberately **conservative** (single-elevation worst
 * case, no irradiance weighting). It's a yes/no "should I worry"
 * pre-flight gate, not a precise error model. Tree shadows, polygon-edge
 * fetch limits, terrain, and atmospheric effects are not modelled.
 */

/** Day-of-year of the first day of each month, non-leap year. Index 0 unused. */
const MONTH_FIRST_DOY = [0, 1, 32, 60, 91, 121, 152, 182, 213, 244, 274, 305, 335] as const

/** Days per month, non-leap year. Index 0 = January. */
const DAYS_PER_MONTH = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31] as const

/**
 * Severity levels in monotonic increasing order of concern.
 * `info` is reserved for cases where the question doesn't apply
 * (no positive-elevation hours in the window, or invalid input).
 */
export const SUN_CONTEXT_SEVERITY_LEVELS = [
  'info',
  'ok',
  'marginal',
  'warning',
  'critical',
] as const

export type SunContextSeverity = (typeof SUN_CONTEXT_SEVERITY_LEVELS)[number]

/** Structured result returned by `estimateSunContextLoss`. */
export interface SunContextResult {
  severity: SunContextSeverity
  /** Human-readable explanation suitable for a banner. */
  message: string
  /** Lowest above-horizon sun elevation (°). `null` if no positive samples. */
  minSunElevationDeg: number | null
  minSunElevationMonth: number | null
  minSunElevationDay: number | null
  minSunElevationHour: number | null
  /** Hemisphere/season/time-band label, e.g. `"Northern hemisphere, winter, late morning"`. */
  pattern: string | null
  /** Tallest building whose full shadow fits inside `bufferM` at the worst-case elevation. */
  bufferBreakevenHeightM: number
  /** Shadow length of a `typicalBuildingHeightM` building at worst-case elevation. */
  shadowAtTypicalBuildingM: number
  /** Shadow length of a `maxBuildingHeightM` building. `null` if not supplied. */
  shadowAtMaxBuildingM: number | null
}

function doy(month: number, day: number): number {
  return MONTH_FIRST_DOY[month] + day - 1
}

/**
 * Approximate solar elevation in degrees.
 *
 * Uses a sinusoidal declination model
 * (`δ ≈ 23.45° · sin(360°/365 · (n − 81))`) and the standard altitude
 * formula. Equation-of-time and atmospheric refraction are intentionally
 * not modelled — accuracy is well within the ~5° tolerance required for
 * a pre-flight gate.
 */
export function solarElevationDeg(latDeg: number, dayOfYear: number, solarHour: number): number {
  const declDeg = 23.45 * Math.sin(((360.0 / 365.0) * (dayOfYear - 81) * Math.PI) / 180)
  const decl = (declDeg * Math.PI) / 180
  const lat = (latDeg * Math.PI) / 180
  const hourAngle = (15.0 * (solarHour - 12.0) * Math.PI) / 180
  let sinAlt =
    Math.sin(lat) * Math.sin(decl) + Math.cos(lat) * Math.cos(decl) * Math.cos(hourAngle)
  sinAlt = Math.max(-1.0, Math.min(1.0, sinAlt))
  return (Math.asin(sinAlt) * 180) / Math.PI
}

/**
 * Geometric buffer needed for a single building's full shadow to fit.
 * Returns `Infinity` for non-positive sun elevations.
 */
export function requiredBufferM(buildingHeightM: number, sunElevationDeg: number): number {
  if (sunElevationDeg <= 0) return Number.POSITIVE_INFINITY
  return buildingHeightM / Math.tan((sunElevationDeg * Math.PI) / 180)
}

function classifyPattern(lat: number, month: number, hour: number): string {
  const hemisphere = lat >= 0 ? 'Northern' : 'Southern'
  let season: string
  if ((lat >= 0 && [11, 12, 1, 2].includes(month)) || (lat < 0 && [5, 6, 7, 8].includes(month))) {
    season = 'winter'
  } else if (
    (lat >= 0 && [5, 6, 7, 8].includes(month)) ||
    (lat < 0 && [11, 12, 1, 2].includes(month))
  ) {
    season = 'summer'
  } else {
    season = 'shoulder season'
  }
  let timeBand: string
  if (hour < 9) timeBand = 'early morning'
  else if (hour < 12) timeBand = 'late morning'
  else if (hour < 14) timeBand = 'midday'
  else if (hour < 17) timeBand = 'afternoon'
  else timeBand = 'late afternoon'
  return `${hemisphere} hemisphere, ${season}, ${timeBand}`
}

function emptyResult(severity: SunContextSeverity, message: string): SunContextResult {
  return {
    severity,
    message,
    minSunElevationDeg: null,
    minSunElevationMonth: null,
    minSunElevationDay: null,
    minSunElevationHour: null,
    pattern: null,
    bufferBreakevenHeightM: 0.0,
    shadowAtTypicalBuildingM: Number.POSITIVE_INFINITY,
    shadowAtMaxBuildingM: null,
  }
}

export interface SunContextInput {
  /** Polygon centroid latitude (°). Drives sun-angle math. */
  lat: number
  /** Polygon centroid longitude (°). Drives clock→solar hour correction. */
  lon?: number
  /**
   * Locale's clock offset from UTC (hours). `undefined` approximates as
   * `round(lon / 15)` — fine for meridian-aligned zones, first-order for the rest.
   */
  timezoneOffsetH?: number
  startMonth: number
  startDay: number
  startHour: number
  endMonth: number
  endDay: number
  endHour: number
  /** Effective per-cell context buffer (m). Default 77 = `SOLAR_TILING_CONFIG.contextSizeM` margin. */
  bufferM?: number
  /** Reference building height for severity. Default 25 m (European mid-rise). */
  typicalBuildingHeightM?: number
  /**
   * Optional worst-case height. When supplied, drives severity via
   * `breakeven / max(typical, max)` so a single tall outlier doesn't slip
   * past as `ok`.
   */
  maxBuildingHeightM?: number
}

/**
 * Estimate whether a tile geometry-context buffer is sufficient.
 *
 * Never throws on bad input — returns `severity: "info"` with a diagnostic
 * message instead.
 */
export function estimateSunContextLoss(input: SunContextInput): SunContextResult {
  const {
    lat,
    lon = 0.0,
    timezoneOffsetH,
    startMonth,
    startDay,
    startHour,
    endMonth,
    endDay,
    endHour,
    bufferM = 77.0,
    typicalBuildingHeightM = 25.0,
    maxBuildingHeightM,
  } = input

  if (typicalBuildingHeightM <= 0) {
    return emptyResult(
      'info',
      'Cannot evaluate: typicalBuildingHeightM must be positive.',
    )
  }

  const bounds: Array<[string, number, number, number]> = [
    ['startMonth', startMonth, 1, 12],
    ['endMonth', endMonth, 1, 12],
    ['startDay', startDay, 1, 31],
    ['endDay', endDay, 1, 31],
    ['startHour', startHour, 0, 23],
    ['endHour', endHour, 0, 23],
  ]
  for (const [label, value, lo, hi] of bounds) {
    if (!Number.isInteger(value) || value < lo || value > hi) {
      return emptyResult('info', `Cannot evaluate: ${label}=${value} out of range [${lo}, ${hi}].`)
    }
  }
  if (lat < -90 || lat > 90) {
    return emptyResult('info', `Cannot evaluate: lat=${lat} out of range [-90, 90].`)
  }
  if (lon < -180 || lon > 180) {
    return emptyResult('info', `Cannot evaluate: lon=${lon} out of range [-180, 180].`)
  }

  // Build the month list; handle year-wrap (e.g. Nov→Feb)
  const months: number[] =
    startMonth <= endMonth
      ? Array.from({ length: endMonth - startMonth + 1 }, (_, i) => startMonth + i)
      : [
          ...Array.from({ length: 13 - startMonth }, (_, i) => startMonth + i),
          ...Array.from({ length: endMonth }, (_, i) => 1 + i),
        ]

  const tzOffset = timezoneOffsetH ?? Math.round(lon / 15.0)
  const solarHourOffset = lon / 15.0 - tzOffset

  const positiveAlts: Array<[number, number, number, number]> = []
  let overallMin: [number, number, number, number] = [90.0, 0, 0, 0]
  let samples = 0
  const nMonths = months.length

  for (let idx = 0; idx < nMonths; idx++) {
    const m = months[idx]
    const isFirst = idx === 0
    const isLast = idx === nMonths - 1
    const dFirst = isFirst ? startDay : 1
    const dLast = isLast ? endDay : DAYS_PER_MONTH[m - 1]
    const dStart = Math.max(1, Math.min(dFirst, DAYS_PER_MONTH[m - 1]))
    const dEnd = Math.max(0, Math.min(DAYS_PER_MONTH[m - 1], dLast))
    if (dEnd < dStart) continue
    for (let d = dStart; d <= dEnd; d++) {
      const dayOfYear = doy(m, d)
      for (let h = startHour; h <= endHour; h++) {
        const solarH = h + solarHourOffset
        const alt = solarElevationDeg(lat, dayOfYear, solarH)
        samples++
        if (alt < overallMin[0]) overallMin = [alt, m, d, h]
        if (alt >= 1.0) positiveAlts.push([alt, m, d, h])
      }
    }
  }

  if (samples === 0) {
    return emptyResult(
      'info',
      'Cannot evaluate: the supplied date range produced zero samples ' +
        '(startDay exceeds the maximum day for the only month sampled).',
    )
  }

  if (positiveAlts.length === 0) {
    return {
      severity: 'info',
      message:
        `No useful direct sun in the window at lat ${lat.toFixed(2)}°: ` +
        `every sampled hour is below the horizon. The context-buffer ` +
        `warning does not apply because direct sun hours will be ` +
        `approximately zero everywhere.`,
      minSunElevationDeg: overallMin[0],
      minSunElevationMonth: overallMin[1] || null,
      minSunElevationDay: overallMin[2] || null,
      minSunElevationHour: overallMin[3] || null,
      pattern: null,
      bufferBreakevenHeightM: 0.0,
      shadowAtTypicalBuildingM: Number.POSITIVE_INFINITY,
      shadowAtMaxBuildingM:
        maxBuildingHeightM !== undefined ? Number.POSITIVE_INFINITY : null,
    }
  }

  // Worst-case (lowest above-horizon) sample drives severity
  let minSample = positiveAlts[0]
  for (const s of positiveAlts) if (s[0] < minSample[0]) minSample = s
  const [minAlt, mm, md, mh] = minSample

  const tanAlt = Math.tan((minAlt * Math.PI) / 180)
  const breakevenHeight = bufferM * tanAlt
  const shadowTypical = typicalBuildingHeightM / tanAlt
  const shadowMax = maxBuildingHeightM !== undefined ? maxBuildingHeightM / tanAlt : null

  const pattern = classifyPattern(lat, mm, mh)
  const when = `${String(mm).padStart(2, '0')}-${String(md).padStart(2, '0')} ${String(mh).padStart(2, '0')}:00`
  const severityHeight = Math.max(typicalBuildingHeightM, maxBuildingHeightM ?? 0.0)
  const heightLabel =
    `${typicalBuildingHeightM.toFixed(0)} m typical` +
    (maxBuildingHeightM !== undefined ? ` / ${maxBuildingHeightM.toFixed(0)} m max` : '')
  const ratio = breakevenHeight / severityHeight

  let severity: SunContextSeverity
  let message: string
  if (ratio >= 1.0) {
    severity = 'ok'
    message =
      `Context buffer is sufficient. The lowest sun elevation in this window ` +
      `is ${minAlt.toFixed(0)}° on ${when} (${pattern}); the ${bufferM.toFixed(0)} m ` +
      `buffer covers shadows from buildings up to ${breakevenHeight.toFixed(0)} m, ` +
      `exceeding the configured ${heightLabel}.`
  } else if (ratio >= 0.5) {
    severity = 'marginal'
    message =
      `Context buffer is borderline. At ${minAlt.toFixed(0)}° sun on ${when} ` +
      `(${pattern}) the ${bufferM.toFixed(0)} m buffer covers buildings up to ` +
      `${breakevenHeight.toFixed(0)} m. Buildings taller than ` +
      `${breakevenHeight.toFixed(0)} m within ${(shadowTypical - bufferM).toFixed(0)} m ` +
      `of a tile edge will lose some shadow context. Cell interiors are ` +
      `reliable; tile edges may show artefacts.`
  } else if (ratio >= 0.2) {
    severity = 'warning'
    message =
      `Context buffer is too small for the chosen sun angle. At ${minAlt.toFixed(0)}° ` +
      `on ${when} (${pattern}), ${heightLabel} buildings cast approximately ` +
      `${shadowTypical.toFixed(0)} m shadows but the buffer is only ` +
      `${bufferM.toFixed(0)} m. Shadows from buildings up to ` +
      `${(shadowTypical - bufferM).toFixed(0)} m beyond each tile edge are not ` +
      `modelled. Consider using a 50% tile overlap or restricting the time ` +
      `window to higher-sun hours.`
  } else {
    severity = 'critical'
    message =
      `Context buffer is severely insufficient. Sun elevation reaches ` +
      `${minAlt.toFixed(0)}° on ${when} (${pattern}). The ${bufferM.toFixed(0)} m ` +
      `buffer covers only buildings up to ${breakevenHeight.toFixed(1)} m, well ` +
      `below the configured ${heightLabel}. Most shadow context is missing at ` +
      `tile edges; results are reliable only deep in tile interiors. Recommend ` +
      `either restricting the time window above the horizon or increasing the ` +
      `geometry-context size.`
  }

  return {
    severity,
    message,
    minSunElevationDeg: minAlt,
    minSunElevationMonth: mm,
    minSunElevationDay: md,
    minSunElevationHour: mh,
    pattern,
    bufferBreakevenHeightM: breakevenHeight,
    shadowAtTypicalBuildingM: shadowTypical,
    shadowAtMaxBuildingM: shadowMax,
  }
}

/**
 * Raised by the opt-in pre-flight gate when the configuration is unlikely
 * to produce reliable results. Only thrown when caller passes
 * `mode: "raise"` to `runPreflightSafely`.
 */
export class PreflightWarning extends Error {
  constructor(message: string) {
    super(message)
    this.name = 'PreflightWarning'
  }
}
